const confirmed = await foundry.applications.api.DialogV2.confirm({
      window: { title: "Clear All Tags" },
      content: "<p>This will delete all tags, subtags, and module assignments. Are you sure?</p>"
  });
  if (!confirmed) return;

  const empty = { tags: [], subtags: [], assignments: {} };
  const payload = JSON.stringify(empty, null, 2);
  const file = new File([payload], "module-tags.json", { type: "application/json" });
  await FilePicker.upload("data", "bbmm-data", file, { notify: false });

  ui.notifications.info("BBMM: All tags cleared. Reload to refresh the tag manager.");
